# dual skeptic-H1 · S04-T1-B-E3
def zip_strict(a, b):
    if len(a) != len(b):
        raise ValueError("longitudes distintas")
    return list(zip(a, b))
try:
    zip_strict([1, 2, 3], [10, 20])
except ValueError:
    print("DESALINEADO")
try:
    zip_strict([1, 2], [3, 4])
    print("OK")
except ValueError:
    print("DESALINEADO")

