# dual skeptic-H1 · S04-T3-A-E1
sts = ["accept", "reject", "accept"]
n_accept = n_reject = n_total = 0
for s in sts:
    n_total += 1
    if s == "accept":
        n_accept += 1
    elif s == "reject":
        n_reject += 1
print(n_accept, n_reject, n_total)

